const fs = require('fs');
const outputDir = $('Code: Create Output Folder').item.json.outputDir;
const datePrefix = $('Code: Create Output Folder').item.json.datePrefix;
const body = $input.first().json;
const err = $input.first().error;
const ts = new Date().toISOString();
const logPath = `${outputDir}/ingest-error.log`;

// Case 1: HTTP-level failure (non-2xx after retry exhaustion, surfaced by
// onError=continueRegularOutput).
if (err) {
  const report = `[${ts}] /ingest failed after retry\n` +
                 `status: ${err.httpCode || 'n/a'}\n` +
                 `message: ${err.message || JSON.stringify(err)}\n` +
                 `response: ${JSON.stringify(err.response || body || {}, null, 2)}\n`;
  fs.writeFileSync(logPath, report, 'utf8');
  return { json: { ingest_status: 'failed', ingest_error: err.message || 'unknown', datePrefix, outputDir } };
}

// Case 2: HTTP 2xx but the body is not the expected ingest-response shape.
if (!body || typeof body.chunks_written !== 'number') {
  const report = `[${ts}] /ingest returned unexpected response shape\n` +
                 `body: ${JSON.stringify(body || {}, null, 2)}\n`;
  fs.writeFileSync(logPath, report, 'utf8');
  return { json: { ingest_status: 'failed', ingest_error: 'unexpected response shape', datePrefix, outputDir } };
}

// Case 3: HTTP 2xx with partial failure. /ingest returns 200 even when
// chunks_failed > 0 because per-chunk Stage C/B LLM failures do not abort
// the session. Surface them as a partial-success log so the operator
// notices and can re-run with force_reextract=true when the upstream
// issue is resolved.
if ((body.chunks_failed || 0) > 0) {
  const warnings = body.warnings || [];
  const warningsText = warnings.length ? ('\n  - ' + warnings.join('\n  - ')) : ' (none)';
  const report = `[${ts}] /ingest partial failure\n` +
                 `chunks_written:  ${body.chunks_written}\n` +
                 `chunks_failed:   ${body.chunks_failed}\n` +
                 `chunks_skipped:  ${body.chunks_skipped_idempotent}\n` +
                 `chunks_by_type:  ${JSON.stringify(body.chunks_by_type || {})}\n` +
                 `warnings:${warningsText}\n\n` +
                 `Partial failures typically mean LLM retry exhaustion for\n` +
                 `individual chunks. Re-run with force_reextract=true once\n` +
                 `the underlying rate-limit or API issue resolves.\n`;
  fs.writeFileSync(logPath, report, 'utf8');
  return { json: { ...body, ingest_status: 'partial', datePrefix, outputDir } };
}

// Case 4: clean success. Remove any stale ingest-error.log left by a prior
// failed or partial run so the output directory accurately reflects the
// current state (empty log would confuse operators; no log == success).
if (fs.existsSync(logPath)) {
  fs.unlinkSync(logPath);
}
return { json: { ...body, ingest_status: 'ok', datePrefix, outputDir } };
